class MiniCircuit:
    def __init__(self, n):
        self.n = n
        self.ops = []

    def add(self, gate, qubits):
        self.ops.append((gate, qubits))
        return self

    def compose(self, other, qubit_map=None):
        if qubit_map is None:
            qubit_map = list(range(other.n))
        for gate, qubits in other.ops:
            mapped = [qubit_map[q] for q in qubits]
            self.ops.append((gate, mapped))
        return self

c1 = MiniCircuit(2)
c1.add('H', [0])
c2 = MiniCircuit(1)
c2.add('X', [0])
c1.compose(c2, [1])
print(c1.ops)

def inverse_circuit(ops):
    inv = []
    for op in reversed(ops):
        gate, qubits, param = op
        if param is not None:
            inv.append((gate, qubits, -param))
        else:
            inv.append(op)  # Self-inverse gates like CX
    return inv

ops = [('RX', 0, 0.5), ('RY', 1, 1.0), ('CX', (0,1), None)]
inv = inverse_circuit(ops)
print(inv)
